#include <gtest/gtest.h>
#include <solvers/fish.h>

TEST(Test2Fish, XWing1){
    //#X-Wing: 2 r38 c34 => r1c34,r2c3<>2
    Inst inst = {0x20,0x2F,0x7F,0xF2,0xF3,1,0x02,0x01, 0x03,0x01,0x12,0x01};
    std::vector<uint16_t> executees = {0x0201, 0x0301,0x1201};
    Grid grid("");
    findFish(grid, 2);
    EXPECT_EQ(grid.instructions, inst);
    EXPECT_EQ(grid.execution.mode, false);
    EXPECT_EQ(grid.execution.executees, executees);
}

